svg.script:
//
(function() {
  var svg          = document.getElementById('root');
  var dataLayerEl  = document.getElementById('data-layer');
  var ns           = 'http://www.w3.org/2000/svg';
  var dotsLayer    = document.getElementById('dots-layer');
  var tipLayer     = document.getElementById('tip-layer');

  /* §2 — isDark hoisted before all build and animation code */
  var isDark = false;

  var series = [
    { id:1, cls:'series-1', label:'Cyan',    vals:[32,38,41,48,52,61,68,72], ys:[372,348,336,308,292,256,228,212] },
    { id:2, cls:'series-2', label:'Violet',  vals:[28,31,35,40,44,49,55,62], ys:[388,376,360,340,324,304,280,252] },
    { id:3, cls:'series-3', label:'Emerald', vals:[18,22,25,29,25,28,31,35], ys:[428,412,400,384,400,388,376,360] },
    { id:4, cls:'series-4', label:'Amber',   vals:[12,15,18,14,17,20,16,22], ys:[452,440,428,444,432,420,436,412] },
    { id:5, cls:'series-5', label:'Slate',   vals:[10,13,11,15,13,17,15,19], ys:[460,448,456,440,448,432,440,424] },
  ];

  var aOpacity = [0.28, 0.24, 0.20, 0.18, 0.14];

  var defs = svg.querySelector('defs');
  series.forEach(function(s, i) {
    var grad = document.createElementNS(ns, 'linearGradient');
    grad.setAttribute('id', 'a'+s.id);
    grad.setAttribute('x1','0'); grad.setAttribute('y1','0');
    grad.setAttribute('x2','0'); grad.setAttribute('y2','1');
    var s0 = document.createElementNS(ns, 'stop');
    s0.setAttribute('id','a'+s.id+'s0'); s0.setAttribute('offset','0%');
    s0.setAttribute('stop-opacity', aOpacity[i]);
    var s1 = document.createElementNS(ns, 'stop');
    s1.setAttribute('id','a'+s.id+'s1'); s1.setAttribute('offset','100%');
    s1.setAttribute('stop-opacity','0.02');
    grad.appendChild(s0); grad.appendChild(s1); defs.appendChild(grad);
    var area = document.getElementById('area-'+s.id);
    if (area) area.setAttribute('fill','url(#a'+s.id+')');
  });

  function syncGradients() {
    var probe = document.createElementNS(ns, 'rect');
    probe.style.visibility='hidden'; probe.style.position='absolute';
    svg.appendChild(probe);
    series.forEach(function(s) {
      probe.setAttribute('class', s.cls);
      var color = window.getComputedStyle(probe).fill;
      var s0=document.getElementById('a'+s.id+'s0'), s1=document.getElementById('a'+s.id+'s1');
      if (s0) s0.setAttribute('stop-color', color);
      if (s1) s1.setAttribute('stop-color', color);
      var area=document.getElementById('area-'+s.id);
      if (area) area.setAttribute('fill','url(#a'+s.id+')');
    });
    svg.removeChild(probe);
  }

  var quarters = ["Q1 '22","Q2 '22","Q3 '22","Q4 '22","Q1 '23","Q2 '23","Q3 '23","Q4 '23"];
  var xs = [68,180,291,403,515,627,738,850];
  var allTips = {};

  function el(tag, attrs) {
    var e = document.createElementNS(ns, tag);
    Object.keys(attrs).forEach(function(k){ e.setAttribute(k, attrs[k]); });
    return e;
  }

  function setHover(activeSid) {
    dataLayerEl.classList.add('hovering');
    /* §4 — clear all stale .active before setting new active series */
    series.forEach(function(s) {
      var line = document.getElementById('line-'+s.id);
      var area = document.getElementById('area-'+s.id);
      if (line) line.classList.remove('active');
      if (area) area.classList.remove('active');
      xs.forEach(function(_, qi) {
        var inner = document.querySelector('#d'+s.id+'_'+qi+' .dot-inner');
        if (inner) inner.classList.remove('active');
      });
    });
    series.forEach(function(s) {
      var isActive = (s.id === activeSid);
      var line = document.getElementById('line-'+s.id);
      var area = document.getElementById('area-'+s.id);
      if (line) line.classList.toggle('active', isActive);
      if (area) area.classList.toggle('active', isActive);
      xs.forEach(function(_, qi) {
        var inner = document.querySelector('#d'+s.id+'_'+qi+' .dot-inner');
        if (inner) inner.classList.toggle('active', isActive);
      });
    });
  }

  function clearHover() {
    dataLayerEl.classList.remove('hovering');
    series.forEach(function(s) {
      var line=document.getElementById('line-'+s.id), area=document.getElementById('area-'+s.id);
      if (line) line.classList.remove('active');
      if (area) area.classList.remove('active');
      xs.forEach(function(_, qi) {
        var inner=document.querySelector('#d'+s.id+'_'+qi+' .dot-inner');
        if (inner) inner.classList.remove('active');
      });
    });
  }

  series.forEach(function(s) {
    xs.forEach(function(x, qi) {
      var y=s.ys[qi], key=s.id+'_'+qi;
      var delay=((s.id-1)*0.25+qi*0.06)+'s';

      var dg=el('g',{'class':'dot-g',id:'d'+key});
      var inner=el('g',{'class':'dot-inner',style:'transform-origin:'+x+'px '+y+'px'});
      inner.style.animation='popDot 0.35s cubic-bezier(0.34,1.4,0.64,1) '+delay;
      inner.addEventListener('animationend',function(){
        inner.style.animation='none';
        inner.classList.add('visible');
      },{once:true});
      var dot=el('circle',{cx:x,cy:y,r:5,'class':s.cls,stroke:'none'});
      inner.appendChild(dot); dg.appendChild(inner); dotsLayer.appendChild(dg);

      var TAIL=14, bh=44, rx=8, tw=10, PAD=20;

      var tipG=el('g',{'class':'tip',id:'t'+key});
      tipLayer.appendChild(tipG); allTips[key]=tipG;

      // Build text nodes first so getBBox() can measure actual rendered widths
      var tv=el('text',{x:0,y:12,'text-anchor':'middle','dominant-baseline':'central','class':'tip-value'});
      tv.textContent='$'+s.vals[qi]+'M'; tipG.appendChild(tv);
      var tl=el('text',{x:0,y:30,'text-anchor':'middle','dominant-baseline':'central','class':'tip-label'});
      tl.textContent=s.label+' · '+quarters[qi]; tipG.appendChild(tl);

      // Measure actual rendered widths with getBBox(), size bubble around content
      var valW = tv.getBBox().width + PAD;
      var lblW = tl.getBBox().width + PAD;
      var hw   = Math.max(valW, lblW, 60) / 2;
      var bw   = hw * 2;

      // Clamp centre-x so bubble never exits card edges (viewBox width = 1100)
      var bCx = Math.max(hw + 8, Math.min(x, 1100 - hw - 8));
      // Position above the dot; flip below if near top of plot area
      var flip = (y - bh - TAIL - 10) < 100;
      var bCy  = flip ? (y + TAIL + 6) : (y - bh - TAIL - 6);

      // Translate the whole tip group so local coords centre on bCx, top at bCy
      tipG.setAttribute('transform','translate('+bCx+','+bCy+')');

      // tip-bg rect — fill only, no stroke
      var bgRect = el('rect',{x:-hw,y:0,width:bw,height:bh,rx:rx,'class':'tip-bg'});
      tipG.insertBefore(bgRect, tv);

      // tip-border path — open rounded-rect with gap at tail root (no Z)
      function makeBorderPath(hw, bh, rx, tw, flip) {
        if (!flip) {
          // gap at bottom centre — tail points down
          return 'M'+tw+','+bh
            +' L'+(hw-rx)+','+bh+' Q'+hw+','+bh+' '+hw+','+(bh-rx)
            +' L'+hw+','+rx+' Q'+hw+',0 '+(hw-rx)+',0'
            +' L'+(-(hw-rx))+',0 Q'+(-hw)+',0 '+(-hw)+','+rx
            +' L'+(-hw)+','+(bh-rx)+' Q'+(-hw)+','+bh+' '+(-(hw-rx))+','+bh
            +' L'+(-tw)+','+bh;
        } else {
          // gap at top centre — tail points up
          return 'M'+(-tw)+',0'
            +' L'+(-(hw-rx))+',0 Q'+(-hw)+',0 '+(-hw)+','+rx
            +' L'+(-hw)+','+(bh-rx)+' Q'+(-hw)+','+bh+' '+(-(hw-rx))+','+bh
            +' L'+(hw-rx)+','+bh+' Q'+hw+','+bh+' '+hw+','+(bh-rx)
            +' L'+hw+','+rx+' Q'+hw+',0 '+(hw-rx)+',0'
            +' L'+tw+',0';
        }
      }
      var borderPath = el('path',{d:makeBorderPath(hw,bh,rx,tw,flip),'class':'tip-border'});
      tipG.insertBefore(borderPath, tv);

      // tip-tail triangle — root points align exactly to tip-border gap endpoints
      var tailPath;
      if (!flip) {
        tailPath = el('path',{d:'M'+tw+','+bh+' L0,'+(bh+TAIL)+' L'+(-tw)+','+bh,'class':'tip-tail'});
      } else {
        tailPath = el('path',{d:'M'+(-tw)+',0 L0,'+(-TAIL)+' L'+tw+',0','class':'tip-tail'});
      }
      tipG.insertBefore(tailPath, tv);

      var ch=document.getElementById('ch'+qi);
      dg.addEventListener('mouseenter',function(){
        allTips[key].style.opacity='1';
        if(ch) ch.style.opacity='1';
        dot.setAttribute('r','7');
        setHover(s.id);
      });
      dg.addEventListener('mouseleave',function(){
        allTips[key].style.opacity='';
        if(ch) ch.style.opacity='';
        dot.setAttribute('r','5');
        clearHover();
      });
    });
  });

  // gate hover on .data-layer.ready after last dot animation finishes
  var lastDelay=(series.length-1)*0.25+(xs.length-1)*0.06;
  setTimeout(function(){ dataLayerEl.classList.add('ready'); },(lastDelay+0.35)*1000+100);

  function setMode(wantDark) {
    if(wantDark===isDark) return;
    isDark=wantDark;
    var thumb=document.getElementById('tthumb'),lbl=document.getElementById('tlabel');
    if(wantDark){svg.classList.add('dark');thumb.setAttribute('cx','52');lbl.textContent='Light';}
    else{svg.classList.remove('dark');thumb.setAttribute('cx','16');lbl.textContent='Dark';}
    syncGradients();
  }

  syncGradients();
  document.getElementById('dark-toggle').addEventListener('click',function(){setMode(!isDark);});
  document.getElementById('print-toggle').addEventListener('click',function(){
    var thumb=document.getElementById('pthumb'),lbl=document.getElementById('plabel');
    if(svg.classList.toggle('print')){thumb.setAttribute('cx','52');lbl.textContent='Screen';}
    else{thumb.setAttribute('cx','16');lbl.textContent='Print';}
  });
  window.setMode=setMode;
  window.addEventListener('message',function(e){if(e.data&&e.data.type==='setMode')setMode(e.data.dark);});
  setMode(window.location.href.indexOf('theme=dark')!==-1);
})();
//
